const entrada = $input.first().json;
const texto = String(entrada.cenarios_gherkin || '').replace(/\r\n/g, '\n').trim();
if (!texto) throw new Error('Nenhum cenário Gherkin foi informado.');

let blocos = texto.split(/(?=^\s*(?:Cenário|Scenario):)/gmi).filter((bloco) => /^\s*(?:Cenário|Scenario):/i.test(bloco));
if (blocos.length === 0) blocos = [texto];

const executionId = `n8n-${$execution.id}`;
const slug = (valor) => String(valor).normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 50) || 'cenario';

return blocos.map((bloco, indice) => {
  const tituloEncontrado = bloco.match(/^\s*(?:Cenário|Scenario):\s*([^\n]+)/i);
  const titulo = tituloEncontrado ? tituloEncontrado[1].trim() : `Cenário ${indice + 1}`;
  const scenarioId = `CT-${String(indice + 1).padStart(3, '0')}-${slug(titulo)}`;
  const { cenarios_gherkin, ...base } = entrada;
  return {
    json: {
      ...base,
      execution_id: executionId,
      scenario_index: indice + 1,
      scenario_id: scenarioId,
      scenario_title: titulo,
      cenario: bloco.trim(),
      evidence_prefix: `${entrada.diretorio_evidencias}\\${executionId}-${scenarioId}`
    }
  };
});

