const origem = $('Loop Sobre Cenários').item.json;
const erro = $json.error;
const saida = $json.output;
const bruto = typeof saida === 'string' ? saida : JSON.stringify(saida ?? '');
let resultado;

if (erro) {
  resultado = {
    status: 'ERRO_AUTOMACAO',
    resumo: 'O agente não conseguiu executar o cenário.',
    passos: [],
    evidencias: [],
    falhas_reais: [],
    falhas_automacao: [typeof erro === 'string' ? erro : (erro.message || JSON.stringify(erro))]
  };
} else if (saida && typeof saida === 'object') {
  resultado = saida;
} else {
  try {
    const limpo = bruto.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
    resultado = JSON.parse(limpo);
  } catch {
    resultado = {
      status: 'ERRO_AUTOMACAO',
      resumo: 'A resposta do agente não estava no formato JSON esperado.',
      passos: [],
      evidencias: [],
      falhas_reais: [],
      falhas_automacao: ['Resposta inválida do agente'],
      resposta_original: bruto
    };
  }
}

const permitidos = ['PASSOU', 'FALHOU', 'BLOQUEADO', 'ERRO_AUTOMACAO'];
if (!permitidos.includes(resultado.status)) resultado.status = 'ERRO_AUTOMACAO';

return {
  json: {
    ...origem,
    status: resultado.status,
    resultado_teste: resultado,
    data_execucao: new Date().toISOString()
  }
};

const resultados = $input.all().map((item) => item.json);
const totais = { PASSOU: 0, FALHOU: 0, BLOQUEADO: 0, ERRO_AUTOMACAO: 0 };
for (const item of resultados) totais[item.status] = (totais[item.status] || 0) + 1;
const primeiro = resultados[0] || {};
return [{
  json: {
    execution_id: primeiro.execution_id || null,
    projeto: primeiro.projeto || null,
    sprint: primeiro.sprint || null,
    sistema_url: primeiro.sistema_url || null,
    inicio_processamento: resultados[0]?.data_execucao || null,
    fim_processamento: new Date().toISOString(),
    total_cenarios: resultados.length,
    totais,
    status_geral: totais.FALHOU > 0 ? 'FALHOU' : (totais.BLOQUEADO > 0 ? 'BLOQUEADO' : (totais.ERRO_AUTOMACAO > 0 ? 'ERRO_AUTOMACAO' : 'PASSOU')),
    resultados
  }
}];
